-- Patchnote 0.8.2 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.8.2', 'minor', '2026-05-19T00:00:00.000Z',
  'Install wizard 2.0, migrate from Overseerr/Jellyseerr/Seerr, plugin SDK i18n',
  'Assistant d''installation 2.0, migration depuis Overseerr/Jellyseerr/Seerr, i18n SDK plugin',
  '[{"type":"feat","titleEn":"Install wizard 2.0 — guided setup with a setup-checklist exit","titleFr":"Assistant d''installation 2.0 — parcours guidé avec sortie sur checklist","descEn":"The install flow was rewritten end-to-end. A 7-step state machine (Secret → Admin → Path → Services → Defaults → Sync → Done) replaces the old monolithic page, with a side-by-side layout (brand panel left, form centered in the viewport) and a vertical stepper that highlights only the active step. Services are picked from a categorized tile grid (media-server / *arr / download-client / indexer / monitoring — required tiles pulled from the connector itself via the new requiredForInstall flag) and configured in a focused modal. A new Defaults step seeds the quality tiers (SD / HD / 4K / 4K HDR), auto-maps every Radarr/Sonarr profile to a tier via name heuristics, and lets you pick a default root folder per media type. The Done step mirrors the admin setup-checklist so the install ends on a fully-wired instance — no more half-finished setups landing in the home page with missing required items.","descFr":"Le parcours d''install a été réécrit de bout en bout. Une machine à états en 7 étapes (Secret → Admin → Parcours → Services → Défauts → Sync → Terminé) remplace l''ancienne page monolithique, avec un layout côte à côte (panneau brand à gauche, formulaire centré dans le viewport) et un stepper vertical qui ne met en avant que l''étape active. Les services se choisissent dans une grille de tuiles catégorisées (serveur média / *arr / client de téléchargement / indexeur / monitoring — les tuiles requises sont tirées du connector lui-même via le nouveau flag requiredForInstall) et se configurent dans un modal dédié. Une nouvelle étape Défauts seed les paliers de qualité (SD / HD / 4K / 4K HDR), mappe automatiquement chaque profil Radarr/Sonarr à un palier via heuristique de nom, et permet de choisir un dossier racine par défaut par type de média. L''étape Terminé reflète la setup-checklist de l''admin pour que l''install se termine sur une instance complète — fini les install à moitié faites qui atterrissent sur la page d''accueil avec des éléments requis manquants."},{"type":"feat","titleEn":"Migrate from Overseerr / Jellyseerr / Seerr at install","titleFr":"Migration depuis Overseerr / Jellyseerr / Seerr à l''install","descEn":"The install wizard gains a Fresh / Migrate path picker. The Migrate path probes the source via /api/v1/settings/{main,radarr,sonarr,plex} (read-only) and bootstraps services, default root folders, locale and quality tiers in one shot. *arr API keys and the Plex token are not exported by the Seerr API surface — the wizard flags them as manual follow-ups and the admin re-finalizes them in Services after install. Users and requests are imported via the existing import flow in the same step. The post-migrate flow now also calls markInstalled() + initScheduler() so the install completes properly (no more wizard re-loop on reload).","descFr":"L''assistant d''installation gagne un sélecteur Fresh / Migration. Le chemin Migration sonde la source via /api/v1/settings/{main,radarr,sonarr,plex} (lecture seule) et bootstrap services, dossiers racine par défaut, locale et paliers de qualité en une fois. Les clés API *arr et le token Plex ne sont pas exportés par l''API Seerr — l''assistant les signale comme actions manuelles et l''admin les re-finalise dans Services après l''install. Utilisateurs et demandes sont importés via le flow d''import existant dans la même étape. Le flow post-migration appelle maintenant markInstalled() + initScheduler() pour que l''install se termine proprement (plus de boucle sur le wizard au reload)."},{"type":"feat","titleEn":"Import users and requests from Overseerr / Jellyseerr / Seerr (admin tab)","titleFr":"Import utilisateurs et demandes depuis Overseerr / Jellyseerr / Seerr (onglet admin)","descEn":"A dedicated Import tab in Admin lets you pull users and request history from any Seerr-family server without going through the install wizard. The flow previews what will land (matched users, conflicts, importable requests with TMDB probe to filter dead IDs), lets you map source users to Oscarr accounts (link, create or skip), and runs the import in the background. Status code 4 (failed/completed) now correctly maps to approved instead of pending. Re-running a preview after a partial import no longer loops on tmdbId 404s.","descFr":"Un onglet Import dédié dans l''Admin permet de récupérer utilisateurs et historique des demandes depuis n''importe quel serveur Seerr-famille sans passer par l''assistant. Le flow montre un aperçu de ce qui sera importé (utilisateurs matchés, conflits, demandes importables avec sonde TMDB pour filtrer les ID morts), permet de mapper les utilisateurs sources aux comptes Oscarr (lier, créer ou ignorer), et exécute l''import en arrière-plan. Le code de statut 4 (failed/completed) est maintenant correctement mappé à approved au lieu de pending. Relancer un aperçu après un import partiel ne boucle plus sur les 404 tmdbId."},{"type":"feat","titleEn":"Quality auto-mapping endpoint","titleFr":"Endpoint d''auto-mapping qualité","descEn":"New admin endpoint POST /admin/quality-mappings/auto scans every enabled Radarr/Sonarr service, fetches its quality profiles, and maps them to the existing Oscarr tiers via name heuristics (HDR + 2160p / 4K / UHD → 4K HDR, 2160p / 4K / UHD → 4K, 1080p / 720p / HD → HD, 480p / SD → SD). Idempotent — re-running skips mappings that already exist. The install wizard calls it automatically after seeding the tiers; admins can also trigger it later from the Quality tab if new profiles get added to a service.","descFr":"Nouvel endpoint admin POST /admin/quality-mappings/auto scanne chaque service Radarr/Sonarr actif, récupère ses profils de qualité, et les mappe aux paliers Oscarr existants via heuristique de nom (HDR + 2160p / 4K / UHD → 4K HDR, 2160p / 4K / UHD → 4K, 1080p / 720p / HD → HD, 480p / SD → SD). Idempotent — relancer skip les mappings qui existent déjà. L''assistant d''installation l''appelle automatiquement après avoir seedé les paliers ; les admins peuvent aussi le relancer depuis l''onglet Qualité si de nouveaux profils sont ajoutés à un service."},{"type":"feat","titleEn":"Plugin SDK gains language + translation helpers","titleFr":"Le SDK plugin gagne des helpers de langue et de traduction","descEn":"@oscarr/sdk now exposes getLang(), a useLanguage() React hook, and a t(dict, lang, key, vars?) helper with fallback chain and interpolation. Plugin frontends can ship their own per-locale dictionaries (~/plugins/<id>/i18n/{en,fr}.ts) and hot-switch when the user changes language in Oscarr — no react-i18next bundle to drag in, no init plumbing to copy from the host app. Core dispatches an oscarr:lang-changed CustomEvent on every language change so the hook re-renders without manual subscription.","descFr":"@oscarr/sdk expose désormais getLang(), un hook React useLanguage(), et un helper t(dict, lang, key, vars?) avec chaîne de fallback et interpolation. Les frontends de plugins peuvent embarquer leurs propres dictionnaires par locale (~/plugins/<id>/i18n/{en,fr}.ts) et hot-switch quand l''utilisateur change la langue dans Oscarr — pas de bundle react-i18next à embarquer, pas de plumbing à copier depuis l''app hôte. Le core dispatche un CustomEvent oscarr:lang-changed à chaque changement de langue pour que le hook re-render sans subscription manuelle."},{"type":"feat","titleEn":"Plugin guard handlers receive request context","titleFr":"Les guards plugin reçoivent le contexte de la requête","descEn":"registerGuards() handlers now get tmdbId, mediaType (movie / tv) and seasons (when applicable) alongside the user — enables plugins like Quotas to gate requests based on what is being requested, not just who is requesting. Existing guards keep working: the new fields are additive and optional.","descFr":"Les handlers registerGuards() reçoivent maintenant tmdbId, mediaType (movie / tv) et seasons (quand applicable) en plus de l''utilisateur — permet aux plugins comme Quotas de gater les demandes selon ce qui est demandé, pas seulement qui demande. Les guards existants continuent de marcher : les nouveaux champs sont additifs et optionnels."},{"type":"feat","titleEn":"Surface undecryptable service credentials in admin UI","titleFr":"Surface les identifiants de services non déchiffrables dans l''UI admin","descEn":"After restoring a backup from another instance (different OSCARR_SECRET_KEY) the encrypted credentials in Service.config can no longer be decrypted with the current master key. Instead of leaking the raw enc:v1:… ciphertext in the admin form, the affected services now show an AlertTriangle per row, an explanatory banner above the list, and the password fields render empty so the admin can re-enter the value cleanly.","descFr":"Après restauration d''un backup d''une autre instance (OSCARR_SECRET_KEY différente), les identifiants chiffrés dans Service.config ne peuvent plus être déchiffrés avec la clé maître courante. Au lieu de laisser apparaître le ciphertext enc:v1:… brut dans le form admin, les services affectés affichent un AlertTriangle par ligne, un bandeau explicatif au-dessus de la liste, et les champs mot de passe s''affichent vides pour que l''admin re-saisisse la valeur proprement."},{"type":"fix","titleEn":"Backend no longer restarts after install","titleFr":"Le backend ne redémarre plus après l''install","descEn":"The /setup/sync handler used to call process.exit(0) right after marking the install complete, relying on docker / systemd to respawn the process. Without a supervisor (dev environment, bare metal without --restart, kubernetes pod with no restartPolicy) the app would stay dark and the user would think the install crashed. The exit is dropped — setup routes are already 403''d by the existing requireNotInstalled preHandler once isInstalled() flips, so the app keeps running cleanly in-process.","descFr":"Le handler /setup/sync appelait process.exit(0) juste après avoir marqué l''install comme complète, en s''appuyant sur docker / systemd pour respawn le process. Sans superviseur (env de dev, bare metal sans --restart, pod k8s sans restartPolicy) l''app restait dark et l''utilisateur croyait que l''install avait crashé. L''exit est retiré — les routes setup sont déjà 403''ées par le preHandler requireNotInstalled une fois isInstalled() basculé, donc l''app continue de tourner proprement in-process."},{"type":"fix","titleEn":"Plugin toggle refuses incompatible / failed plugins","titleFr":"Le toggle plugin refuse les plugins incompatibles / en échec","descEn":"Toggling on a plugin that failed to load (incompatible engines range, missing exports, import-time error) used to throw a cryptic Prisma RecordNotFound on pluginState.update because the row was never upserted. togglePlugin now bails early with a clear error message (the actual compat reason or import error), and the admin UI disables the toggle switch + shows the reason in the tooltip — no more confusing crashes from clicking on a broken plugin.","descFr":"Activer un plugin qui n''a pas chargé (range engines incompatible, exports manquants, erreur à l''import) levait un Prisma RecordNotFound cryptique sur pluginState.update car la row n''avait jamais été upsertée. togglePlugin sort maintenant tôt avec un message d''erreur clair (la vraie raison d''incompat ou l''erreur d''import), et l''UI admin désactive le toggle + montre la raison dans le tooltip — fini les crashs inattendus en cliquant sur un plugin cassé."},{"type":"fix","titleEn":"docker-compose injects OSCARR_SECRET_KEY into the container","titleFr":"docker-compose injecte OSCARR_SECRET_KEY dans le conteneur","descEn":"compose only interpolates .env for YAML substitution, not for container env. The published docker-compose.yml now adds both env_file: - .env (so any variable in .env reaches the container) and an explicit environment: - OSCARR_SECRET_KEY=${OSCARR_SECRET_KEY} (so the boot-time secret check passes). Without this, fresh upgrades on compose deployments would fatal-exit on the new mandatory secret key from 0.8.1.","descFr":"compose n''interpole .env que pour la substitution YAML, pas pour l''env du conteneur. Le docker-compose.yml publié ajoute maintenant à la fois env_file: - .env (pour que toute variable de .env arrive au conteneur) et un environment: - OSCARR_SECRET_KEY=${OSCARR_SECRET_KEY} explicite (pour que le check secret au boot passe). Sans ça, les upgrades neufs sur des déploiements compose fataient sur la nouvelle clé secrète obligatoire de 0.8.1."}]'
) ON CONFLICT ("version") DO NOTHING;
